32	    public JwtAuthenticationFilter jwtAuthenticationFilter() {
33	        return new JwtAuthenticationFilter(jwtTokenProvider);
34	    }
35	
36	    @Bean
37	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
38	
39	        http
40	            .csrf(csrf -> csrf.disable())
41	            .cors(cors -> cors.disable())
42	            .formLogin(form -> form.disable())
43	            .httpBasic(basic -> basic.disable())
44	            .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
45	            .authorizeHttpRequests(auth -> auth
46	                .antMatchers("/api/v1/auth/login").permitAll()
47	                .antMatchers("/api/v1/auth/logout").permitAll()
48	                .antMatchers(HttpMethod.POST, "/api/v1/imports").hasRole("ADMIN")
49	                .anyRequest().authenticated()
50	            )
51	            .addFilterBefore(jwtAuthenticationFilter(), UsernamePasswordAuthenticationFilter.class)
52	            .exceptionHandling(eh -> eh
53	                .authenticationEntryPoint((req, res, ex) -> {
54	                    res.setStatus(HttpStatus.UNAUTHORIZED.value());
55	                    res.setContentType(MediaType.APPLICATION_JSON_VALUE);
56	                    res.setCharacterEncoding("UTF-8");
57	                    ApiResponse<Void> body = ApiResponse.error(
58	                            ErrorCode.AUTH_1002.getCode(),
59	                            ErrorCode.AUTH_1002.getMessage()
60	                    );
61	                    res.getWriter().write(objectMapper.writeValueAsString(body));
62	                })
63	                .accessDeniedHandler((req, res, ex) -> {
64	                    res.setStatus(HttpStatus.FORBIDDEN.value());
65	                    res.setContentType(MediaType.APPLICATION_JSON_VALUE);
66	                    res.setCharacterEncoding("UTF-8");
67	                    ApiResponse<Void> body = ApiResponse.error(
68	                            ErrorCode.COMMON_0003.getCode(),
69	                            ErrorCode.COMMON_0003.getMessage()
70	                    );
71	                    res.getWriter().write(objectMapper.writeValueAsString(body));
72	                })
73	            );
74	
75	        return http.build();
76	    }
77	}
