21	 * CSV 헤더 정확 일치 검증 + 행 단위 streaming.
22	 * BOM(0xFEFF) 첫 1글자 자동 skip. UTF-8 외 인코딩은 IMPORT_3006.
23	 */
24	@Component
25	@Slf4j
26	public class CsvImportParser {
27	
28	    private static final char BOM = '﻿';
29	
30	    @FunctionalInterface
31	    public interface RowConsumer {
32	        void accept(int rowNo, String[] cols);
33	    }
34	
35	    public void validateHeader(Path file, ImportType type) {
36	        try (BufferedReader br = Files.newBufferedReader(file, StandardCharsets.UTF_8);
37	             CSVReader csv = new CSVReaderBuilder(br).build()) {
38	
39	            String[] firstRow = csv.readNext();
40	            if (firstRow == null) {
41	                throw new BusinessException(ErrorCode.IMPORT_3001);
42	            }
43	
44	            // 첫 셀의 BOM 제거
45	            if (firstRow.length > 0 && !firstRow[0].isEmpty() && firstRow[0].charAt(0) == BOM) {
46	                firstRow[0] = firstRow[0].substring(1);
47	            }
48	
49	            String[] expected = type.getHeaders();
50	            if (!Arrays.equals(firstRow, expected)) {
51	                log.warn("[Import] Header mismatch. type={}, expected={}, actual={}",
52	                        type, Arrays.toString(expected), Arrays.toString(firstRow));
53	                throw new BusinessException(ErrorCode.IMPORT_3001);
54	            }
55	
56	        } catch (MalformedInputException | UnmappableCharacterException ex) {
57	            throw new BusinessException(ErrorCode.IMPORT_3006);
58	        } catch (BusinessException ex) {
59	            throw ex;
60	        } catch (IOException | CsvException ex) {
61	            log.error("[Import] CSV parse error during header validation", ex);
62	            throw new BusinessException(ErrorCode.IMPORT_3004);
63	        }
64	    }
