21	    private final Duration expiration;
22	
23	    public JwtTokenProvider(
24	            @Value("${jwt.secret}") String secret,
25	            @Value("${jwt.expiration-minutes}") int expirationMinutes
26	    ) {
27	        this.key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
28	        this.expiration = Duration.ofMinutes(expirationMinutes);
29	    }
30	
31	    public String issue(Long userId, String username, String role) {
32	        Date now = new Date();
33	        Date exp = new Date(now.getTime() + expiration.toMillis());
34	
35	        return Jwts.builder()
36	                .setSubject(username)
37	                .claim("uid", userId)
38	                .claim("role", role)
39	                .setIssuedAt(now)
40	                .setExpiration(exp)
41	                .signWith(key, SignatureAlgorithm.HS256)
42	                .compact();
43	    }
44	
45	    public Claims parse(String token) {
46	        return Jwts.parserBuilder()
47	                .setSigningKey(key)
48	                .build()
49	                .parseClaimsJws(token)
50	                .getBody();
51	    }
52	
53	    public long getExpirationSeconds() {
54	        return expiration.getSeconds();
55	    }
